def save_model():
    """Save the current model to disk."""
    with open(ENCODINGS_PATH, "wb") as f:
        pickle.dump(face_model, f)


def compute_confidence_scores(face_encoding, known_encodings, known_names):
    """
    Compute detailed confidence/probability distribution over all known employees.
    Uses face distance and converts to probability-like scores.
    """
    if not known_encodings:
        return {}

    face_distances = face_recognition.face_distance(known_encodings, face_encoding)

    unique_names = sorted(set(known_names))

    # Aggregate distances per person (take minimum distance for each person)
    person_min_distances = {}
    person_all_distances = {}
    for name, dist in zip(known_names, face_distances):
        if name not in person_all_distances:
            person_all_distances[name] = []
        person_all_distances[name].append(dist)

    for name in unique_names:
        distances = person_all_distances[name]
        person_min_distances[name] = min(distances)

    # Convert distances to similarity scores using exponential decay
    # Lower distance = higher similarity
    similarity_scores = {}
    for name, min_dist in person_min_distances.items():
        # Using a sigmoid-like transformation for better probability interpretation
        # face_distance of 0.6 is typical threshold; we use exponential mapping
        similarity = np.exp(-min_dist * 5)  # Scale factor for sensitivity
        similarity_scores[name] = similarity

    # Normalize to get probability distribution
    total_similarity = sum(similarity_scores.values())
    probability_distribution = {}
    if total_similarity > 0:
        for name in unique_names:
            probability_distribution[name] = similarity_scores[name] / total_similarity
    else:
        uniform_prob = 1.0 / len(unique_names)
        for name in unique_names:
            probability_distribution[name] = uniform_prob

    # Also compute raw confidence based on best match distance
    detailed_scores = {}
    for name in unique_names:
        min_dist = person_min_distances[name]
        avg_dist = np.mean(person_all_distances[name])
        num_samples = len(person_all_distances[name])

        # Linear confidence: 1.0 at distance 0, 0.0 at distance 1.0
        linear_confidence = max(0.0, 1.0 - min_dist)

        detailed_scores[name] = {
            "probability": round(float(probability_distribution[name]), 6),
            "linear_confidence": round(float(linear_confidence), 6),
            "min_face_distance": round(float(min_dist), 6),
            "avg_face_distance": round(float(avg_dist), 6),
            "num_reference_images": num_samples
        }

    return detailed_scores


