@app.post("/employees/{employee_id}/upload-photo")
async def upload_employee_photo(employee_id: str, employee_name: str, file: UploadFile = File(...)):
    """
    Upload a training photo for an employee and update the model.
    """
    global face_model

    contents = await file.read()

    try:
        image = Image.open(BytesIO(contents))
        image_np = np.array(image)
    except Exception as e:
        raise HTTPException(status_code=400, detail=f"Invalid image file: {str(e)}")

    # Detect faces in the image
    face_locations = face_recognition.face_locations(image_np, model="hog")
    if len(face_locations) == 0:
        raise HTTPException(status_code=400, detail="No face detected in the uploaded image")
    if len(face_locations) > 1:
        raise HTTPException(
            status_code=400,
            detail=f"Multiple faces ({len(face_locations)}) detected. Please upload a photo with only one face."
        )

    # Compute face encoding
    face_encodings = face_recognition.face_encodings(image_np, face_locations)
    if len(face_encodings) == 0:
        raise HTTPException(status_code=400, detail="Could not compute face encoding")

    encoding = face_encodings[0]

    # Save the photo
    employee_dir = TRAINING_DIR / f"{employee_id}_{employee_name}"
    employee_dir.mkdir(parents=True, exist_ok=True)
    num_existing = len(list(employee_dir.glob("*")))
    photo_path = employee_dir / f"photo_{num_existing + 1}{Path(file.filename).suffix or '.jpg'}"
    with open(photo_path, "wb") as f:
        f.write(contents)

    # Update model
    display_name = f"{employee_name} ({employee_id})"
    face_model["encodings"].append(encoding)
    face_model["names"].append(display_name)
    face_model["employee_ids"].append(employee_id)

    save_model()

    return {
        "status": "success",
        "message": f"Photo uploaded and face encoding computed for {employee_name}",
        "employee_id": employee_id,
        "employee_name": employee_name,
        "photo_saved": str(photo_path),
        "total_photos_for_employee": num_existing + 1,
        "face_location": face_locations[0]
    }


@app.post("/train")
async def train_from_directory():
    """
    Train/retrain the model from all photos in the employee_photos directory.
    Directory structure: employee_photos/{employee_id}_{name}/photo1.jpg, photo2.jpg, ...
    """
    global face_model

    face_model = {"encodings": [], "names": [], "employee_ids": []}

    if not TRAINING_DIR.exists():
        raise HTTPException(status_code=404, detail="Training directory not found")

    employee_dirs = [d for d in TRAINING_DIR.iterdir() if d.is_dir()]
    if not employee_dirs:
        raise HTTPException(status_code=404, detail="No employee directories found")

    training_summary = []
    total_images = 0
    total_faces = 0

    for emp_dir in employee_dirs:
        dir_name = emp_dir.name
        parts = dir_name.split("_", 1)
        if len(parts) == 2:
            employee_id, employee_name = parts
        else:
            employee_id = dir_name
            employee_name = dir_name

        display_name = f"{employee_name} ({employee_id})"
        image_files = list(emp_dir.glob("*.jpg")) + list(emp_dir.glob("*.jpeg")) + \
                      list(emp_dir.glob("*.png")) + list(emp_dir.glob("*.bmp"))

        employee_face_count = 0
        for img_path in image_files:
            total_images += 1
            try:
                image = face_recognition.load_image_file(str(img_path))
                face_locations = face_recognition.face_locations(image, model="hog")
                face_encodings = face_recognition.face_encodings(image, face_locations)

                for encoding in face_encodings:
                    face_model["encodings"].append(encoding)
                    face_model["names"].append(display_name)
                    face_model["employee_ids"].append(employee_id)
                    employee_face_count += 1
                    total_faces += 1
            except Exception as e:
                print(f"Error processing {img_path}: {e}")
                continue

        training_summary.append({
            "employee_id": employee_id,
            "employee_name": employee_name,
            "images_processed": len(image_files),
            "faces_encoded": employee_face_count
        })

    save_model()

    return {
        "status": "success",
        "total_employees": len(employee_dirs),
        "total_images_processed": total_images,
        "total_face_encodings": total_faces,
        "training_summary": training_summary
    }


@app.post("/recognize")
async def recognize_face(
    file: UploadFile = File(...),
    tolerance: float = 0.6,
    include_unknown_analysis: bool = True
):
    """
    Recognize faces in an uploaded image.
    Returns detailed probability distribution over ALL known employees for each detected face.

    - tolerance: face distance threshold for positive match (default 0.6, lower is stricter)
    - include_unknown_analysis: whether to include analysis for potentially unknown persons
    """
    if not face_model.get("encodings"):
        raise HTTPException(
            status_code=400,
            detail="No trained model available. Please upload employee photos and train first."
        )

    contents = await file.read()

    try:
        image = Image.open(BytesIO(contents))
        image_np = np.array(image)
    except Exception as e:
        raise HTTPException(status_code=400, detail=f"Invalid image file: {str(e)}")

    face_locations = face_recognition.face_locations(image_np, model="hog")

    if len(face_locations) == 0:
        return {
            "status": "no_faces_detected",
            "faces_detected": 0,
            "results": [],
            "security_alert": "No face detected in image"
        }

    face_encodings = face_recognition.face_encodings(image_np, face_locations)

    known_encodings = face_model["encodings"]
    known_names = face_model["names"]

    results = []

    for i, (face_encoding, face_location) in enumerate(zip(face_encodings, face_locations)):
        top, right, bottom, left = face_location

        # Compute detailed confidence scores for ALL known employees
        detailed_scores = compute_confidence_scores(face_encoding, known_encodings, known_names)

        # Sort by probability (descending)
        sorted_scores = dict(
            sorted(detailed_scores.items(), key=lambda x: x[1]["probability"], reverse=True)
        )

        # Determine best match
        best_match_name = None
        best_match_confidence = 0.0
        best_match_distance = float('inf')
        is_known = False

        if sorted_scores:
            best_match_name = list(sorted_scores.keys())[0]
            best_match_info = sorted_scores[best_match_name]
            best_match_confidence = best_match_info["probability"]
            best_match_distance = best_match_info["min_face_distance"]
            is_known = best_match_distance <= tolerance

        # Unknown person analysis
        unknown_analysis = None
        if include_unknown_analysis:
            all_distances = face_recognition.face_distance(known_encodings, face_encoding)
            unknown_analysis = {
                "min_distance_to_any_known": round(float(np.min(all_distances)), 6) if len(all_distances) > 0 else None,
                "max_distance_to_any_known": round(float(np.max(all_distances)), 6) if len(all_distances) > 0 else None,
                "mean_distance_to_all_known": round(float(np.mean(all_distances)), 6) if len(all_distances) > 0 else None,
                "std_distance_to_all_known": round(float(np.std(all_distances)), 6) if len(all_distances) > 0 else None,
                "likely_unknown": not is_known,
                "threshold_used": tolerance
            }

        # Security assessment
        if is_known and best_match_confidence > 0.5:
            security_status = "AUTHORIZED"
        elif is_known and best_match_confidence > 0.3:
            security_status = "LOW_CONFIDENCE_MATCH"
        else:
            security_status = "UNAUTHORIZED_UNKNOWN"

        face_result = {
            "face_index": i,
            "face_location": {
                "top": top,
                "right": right,
                "bottom": bottom,
                "left": left
            },
            "best_match": {
                "identity": best_match_name if is_known else "UNKNOWN",
                "is_recognized": is_known,
                "face_distance": round(float(best_match_distance), 6),
                "confidence": round(float(best_match_confidence), 6)
            },
            "security_status": security_status,
            "probability_distribution": sorted_scores,
            "top_3_matches": {
                name: info for name, info in list(sorted_scores.items())[:3]
            },
            "unknown_person_analysis": unknown_analysis
        }

        results.append(face_result)

    # Overall security assessment
    security_alerts = []
    for r in results:
        if r["security_status"] == "UNAUTHORIZED_UNKNOWN":
            security_alerts.append(
                f"Face #{r['face_index']}: Unknown person detected at location {r['face_location']}"
            )
        elif r["security_status"] == "LOW_CONFIDENCE_MATCH":
            security_alerts.append(
                f"Face #{r['face_index']}: Low confidence match for {r['best_match']['identity']}"
            )

    return {
        "status": "success",
        "faces_detected": len(face_locations),
        "authorized_count": sum(1 for r in results if r["security_status"] == "AUTHORIZED"),
        "unauthorized_count": sum(1 for r in results if r["security_status"] == "UNAUTHORIZED_UNKNOWN"),
        "low_confidence_count": sum(1 for r in results if r["security_status"] == "LOW_CONFIDENCE_MATCH"),
        "security_alerts": security_alerts,
        "results": results
    }


@app.post("/verify")
async def verify_identity(
    employee_id: str,
    file: UploadFile = File(...),
    tolerance: float = 0.5
):
    """
    Verify if the person in the photo matches a specific employee.
    Used for identity verification at security checkpoints.
    """
    if not face_model.get("encodings"):
        raise HTTPException(status_code=400, detail="No trained model available")

    contents = await file.read()

    try:
        image = Image.open(BytesIO(contents))
        image_np = np.array(image)
    except Exception as e:
        raise HTTPException(status_code=400, detail=f"Invalid image file: {str(e)}")

    face_locations = face_recognition.face_locations(image_np, model="hog")
    if len(face_locations) == 0:
        raise HTTPException(status_code=400, detail="No face detected in the image")
    if len(face_locations) > 1:
        raise HTTPException(status_code=400, detail="Multiple faces detected. Please provide a single face image.")

    face_encoding = face_recognition.face_encodings(image_np, face_locations)[0]

    # Get only encodings for the specified employee
    employee_encodings = []
    employee_name = None
    for enc, name, eid in zip(face_model["encodings"], face_model["names"], face_model["employee_ids"]):
        if eid == employee_id:
            employee_encodings.append(enc)
            employee_name = name

    if not employee_encodings:
        raise HTTPException(
            status_code=404,
            detail=f"No face data found for employee ID: {employee_id}"
        )

    distances = face_recognition.face_distance(employee_encodings, face_encoding)
    min_distance = float(np.min(distances))
    avg_distance = float(np.mean(distances))
    is_match = min_distance <= tolerance

    # Also compute scores against all other employees for comparison
    all_scores = compute_confidence_scores(face_encoding, face_model["encodings"], face_model["names"])

    return {
        "status": "success",
        "verification_result": {
            "employee_id": employee_id,
            "employee_name": employee_name,
            "is_verified": is_match,
            "min_face_distance": round(min_distance, 6),
            "avg_face_distance": round(avg_distance, 6),
            "confidence": round(max(0.0, 1.0 - min_distance), 6),
            "tolerance_used": tolerance,
            "num_reference_images": len(employee_encodings)
        },
        "comparative_analysis": all_scores,
        "security_recommendation": "ACCESS GRANTED" if is_match else "ACCESS DENIED"
    }


@app.get("/employees")
async def list_employees():
    """List all registered employees in the model."""
    if not face_model.get("names"):
        return {"status": "success", "employees": [], "total": 0}

    employee_info = {}
    for name, eid in zip(face_model["names"], face_model["employee_ids"]):
        if eid not in employee_info:
            employee_info[eid] = {
                "employee_id": eid,
                "display_name": name,
                "num_face_encodings": 0
            }
        employee_info[eid]["num_face_encodings"] += 1

    return {
        "status": "success",
        "total_employees": len(employee_info),
        "total_encodings": len(face_model["encodings"]),
        "employees": list(employee_info.values())
    }


@app.delete("/employees/{employee_id}")
async def remove_employee(employee_id: str):
    """Remove an employee from the recognition model."""
    global face_model

    indices_to_remove = [
        i for i, eid in enumerate(face_model["employee_ids"]) if eid == employee_id
    ]

    if not indices_to_remove:
        raise HTTPException(status_code=404, detail=f"Employee {employee_id} not found in model")

    removed_name = face_model["names"][indices_to_remove[0]]

    for key in ["encodings", "names", "employee_ids"]:
        face_model[key] = [
            item for i, item in enumerate(face_model[key]) if i not in indices_to_remove
        ]

    save_model()

    return {
        "status": "success",
        "message": f"Removed {removed_name} ({len(indices_to_remove)} encodings)",
        "remaining_employees": len(set(face_model["employee_ids"]))
    }


@app.get("/model/stats")
async def model_statistics():
    """Get detailed model statistics."""
    if not face_model.get("encodings"):
        return {"status": "no_model", "message": "No model trained yet"}

    unique_employees = set(face_model["employee_ids"])
    encodings_per_employee = {}
    for name, eid in zip(face_model["names"], face_model["employee_ids"]):
        if eid not in encodings_per_employee:
            encodings_per_employee[eid] = {"name": name, "count": 0}
        encodings_per_employee[eid]["count"] += 1

    return {
        "status": "success",
        "total_employees": len(unique_employees),
        "total_encodings": len(face_model["encodings"]),
        "avg_encodings_per_employee": round(
            len(face_model["encodings"]) / max(len(unique_employees), 1), 1
        ),
        "encodings_per_employee": encodings_per_employee,
        "model_file_exists": ENCODINGS_PATH.exists(),
        "model_file_size_bytes": ENCODINGS_PATH.stat().st_size if ENCODINGS_PATH.exists() else 0
    }


